content.text:
 1	$pf-v5-global-gutter: 1rem; // Matches --pf-t--global--spacer--gutter--default
 2	$pf-v5-global-gutter--md: 1.5rem; // Matches --pf-t--global--spacer--gutter--default--md
 3	$pf-v5-global--breakpoint--xl: 1200px !default;
 4	
 5	.ocs-form-footer {
 6	  padding: var(--pf-t--global--spacer--300) $pf-v5-global-gutter;
 7	  @media (min-width: $pf-v5-global--breakpoint--xl) {
 8	    padding: var(--pf-t--global--spacer--300) $pf-v5-global-gutter--md;
 9	  }
10	  &__sticky {
11	    position: sticky;
12	    background-color: var(pf-v5-u-background-color-dark-400);
13	    bottom: 0;
14	  }
15	  &__shadow {
16	    box-shadow: var(--pf-t--global--box-shadow--sm-top);
17	  }
18	}

